parameters.jsCode:
for (const item of $input.all()) {
  let body = item.json.email_body || '';

  let newBody = body
    .replace(/\b\d{3}-\d{2}-\d{4}\b/g, '[REDACTED]')
    .replace(/\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b/g, '[REDACTED]')
    .replace(/\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g, '[REDACTED]');

  item.json.hasPII = (newBody !== body);
  item.json.sanitized_body = newBody;
}
return $input.all();

parameters.workflowInputs:
